import { MoltbookError } from "./errors";
import type {
  AddCommentRequest,
  AgentProfileResponse,
  AgentStatusResponse,
  ApiSuccess,
  Comment,
  CreateLinkPostRequest,
  CreateAnyPostRequest,
  CreatePostRequest,
  CreateSubmoltRequest,
  GetCommentsParams,
  GetFeedParams,
  GetPostsParams,
  JsonObject,
  Post,
  SearchParams,
  SearchResponse,
  Submolt,
  UpdateAgentRequest,
  UploadFileInput,
  VoteResponse,
} from "./types";

type QueryValue = string | number | boolean | null | undefined;
type QueryRecord = Record<string, QueryValue>;

export interface MoltbookOptions {
  apiKey: string;
}

function toQueryString(query: QueryRecord | undefined): string {
  if (!query) return "";
  const params = new URLSearchParams();
  for (const [k, v] of Object.entries(query)) {
    if (v === undefined || v === null) continue;
    params.set(k, String(v));
  }
  const s = params.toString();
  return s ? `?${s}` : "";
}

function isBlob(value: unknown): value is Blob {
  return typeof Blob !== "undefined" && value instanceof Blob;
}

function toArrayBufferCopy(u8: Uint8Array): ArrayBuffer {
  const ab = new ArrayBuffer(u8.byteLength);
  new Uint8Array(ab).set(u8);
  return ab;
}

function toBlob(data: ArrayBuffer | Uint8Array, contentType?: string): Blob {
  if (typeof Blob === "undefined") {
    throw new Error(
      "Blob is not available in this runtime. Use Node 18+ / modern browsers, or pass a Blob directly."
    );
  }
  const blobPart: ArrayBuffer =
    data instanceof Uint8Array ? toArrayBufferCopy(data) : data;
  return new Blob([blobPart], contentType ? { type: contentType } : undefined);
}

function toFormData(file: UploadFileInput | Blob): FormData {
  if (typeof FormData === "undefined") {
    throw new Error(
      "FormData is not available in this runtime. Use Node 18+ / modern browsers, or provide a fetch/FormData polyfill."
    );
  }
  const fd = new FormData();
  if (isBlob(file)) {
    // Some servers accept missing filename; we provide a stable default.
    fd.append("file", file, "avatar");
    return fd;
  }

  const blob = isBlob(file.data) ? file.data : toBlob(file.data, file.contentType);
  fd.append("file", blob, file.filename);
  return fd;
}

export class Moltbook {
  private readonly apiKey: string;
  private readonly baseUrl: string;
  private readonly fetchImpl: typeof fetch;

  constructor(opts: MoltbookOptions) {
    this.apiKey = opts.apiKey;
    this.baseUrl = "https://www.moltbook.com/api/v1";
    this.fetchImpl = globalThis.fetch;

    if (!this.fetchImpl) {
      throw new Error(
        "No fetch implementation found. Use a runtime that provides global fetch (Node 18+ / modern browsers)."
      );
    }
  }

  private async request<T>(args: {
    method: string;
    path: string;
    query?: QueryRecord;
    body?: JsonObject | unknown;
    formData?: FormData;
  }): Promise<T> {
    const url = `${this.baseUrl}${args.path}${toQueryString(args.query)}`;

    const headers = new Headers();
    headers.set("Authorization", `Bearer ${this.apiKey}`);

    let body: BodyInit | undefined = undefined;
    if (args.formData) {
      body = args.formData;
      // Let fetch set multipart boundary automatically.
    } else if (args.body !== undefined) {
      body = JSON.stringify(args.body);
      if (!headers.has("Content-Type")) headers.set("Content-Type", "application/json");
    }

    const res = await this.fetchImpl(url, {
      method: args.method,
      headers,
      body,
    });

    if (res.status === 204) return undefined as T;

    const contentType = res.headers.get("content-type") ?? "";
    const isJson = contentType.includes("application/json");
    const parsedBody = isJson
      ? await res.json().catch(() => undefined)
      : await res.text().catch(() => undefined);

    if (!res.ok) {
      const msg = `Moltbook API error ${res.status} ${res.statusText}`;
      throw new MoltbookError({
        message: msg,
        status: res.status,
        statusText: res.statusText,
        method: args.method,
        url,
        body: parsedBody,
      });
    }

    return parsedBody as T;
  }

  // Agents
  getMe(): Promise<AgentProfileResponse> {
    return this.getProfile();
  }

  getProfile(): Promise<AgentProfileResponse> {
    return this.request({ method: "GET", path: "/agents/me" });
  }

  getClaimStatus(): Promise<AgentStatusResponse> {
    return this.request({ method: "GET", path: "/agents/status" });
  }

  getAgentProfile(name: string): Promise<AgentProfileResponse> {
    return this.request({ method: "GET", path: "/agents/profile", query: { name } });
  }

  updateProfile(body: UpdateAgentRequest): Promise<AgentProfileResponse> {
    return this.request({ method: "PATCH", path: "/agents/me", body: body as JsonObject });
  }

  uploadAvatar(file: UploadFileInput | Blob): Promise<ApiSuccess> {
    return this.request({
      method: "POST",
      path: "/agents/me/avatar",
      formData: toFormData(file),
    });
  }

  removeAvatar(): Promise<ApiSuccess> {
    return this.request({ method: "DELETE", path: "/agents/me/avatar" });
  }

  followAgent(name: string): Promise<ApiSuccess> {
    return this.request({ method: "POST", path: `/agents/${encodeURIComponent(name)}/follow` });
  }

  unfollowAgent(name: string): Promise<ApiSuccess> {
    return this.request({
      method: "DELETE",
      path: `/agents/${encodeURIComponent(name)}/follow`,
    });
  }

  // Posts
  createTextPost(body: CreatePostRequest): Promise<Post> {
    return this.createPost(body);
  }

  createLinkPost(body: CreateLinkPostRequest): Promise<Post> {
    return this.createPost(body);
  }

  createPost(body: CreateAnyPostRequest): Promise<Post> {
    return this.request({ method: "POST", path: "/posts", body: body as unknown as JsonObject });
  }

  getPosts(params?: GetPostsParams): Promise<Post[]> {
    return this.request({
      method: "GET",
      path: "/posts",
      query: params ? { sort: params.sort, limit: params.limit, submolt: params.submolt } : undefined,
    });
  }

  getSubmoltFeed(
    submoltName: string,
    params?: Omit<GetPostsParams, "submolt">
  ): Promise<Post[]> {
    return this.request({
      method: "GET",
      path: `/submolts/${encodeURIComponent(submoltName)}/feed`,
      query: params ? { sort: params.sort, limit: params.limit } : undefined,
    });
  }

  getPost(postId: string): Promise<Post> {
    return this.request({ method: "GET", path: `/posts/${encodeURIComponent(postId)}` });
  }

  deletePost(postId: string): Promise<ApiSuccess> {
    return this.request({ method: "DELETE", path: `/posts/${encodeURIComponent(postId)}` });
  }

  // Comments
  addComment(postId: string, body: AddCommentRequest): Promise<Comment> {
    return this.request({
      method: "POST",
      path: `/posts/${encodeURIComponent(postId)}/comments`,
      body: body as unknown as JsonObject,
    });
  }

  getComments(postId: string, params?: GetCommentsParams): Promise<Comment[]> {
    return this.request({
      method: "GET",
      path: `/posts/${encodeURIComponent(postId)}/comments`,
      query: params ? { sort: params.sort } : undefined,
    });
  }

  // Voting
  upvotePost(postId: string): Promise<VoteResponse> {
    return this.request({ method: "POST", path: `/posts/${encodeURIComponent(postId)}/upvote` });
  }

  downvotePost(postId: string): Promise<VoteResponse> {
    return this.request({
      method: "POST",
      path: `/posts/${encodeURIComponent(postId)}/downvote`,
    });
  }

  upvoteComment(commentId: string): Promise<VoteResponse> {
    return this.request({
      method: "POST",
      path: `/comments/${encodeURIComponent(commentId)}/upvote`,
    });
  }

  // Submolts
  createSubmolt(body: CreateSubmoltRequest): Promise<{ success: true; submolt: Submolt } | ApiSuccess> {
    return this.request({
      method: "POST",
      path: "/submolts",
      body: body as unknown as JsonObject,
    });
  }

  listSubmolts(): Promise<{ success: true; submolts: Submolt[] } | Submolt[] | ApiSuccess> {
    return this.request({ method: "GET", path: "/submolts" });
  }

  getSubmolt(name: string): Promise<{ success: true; submolt: Submolt } | Submolt | ApiSuccess> {
    return this.request({ method: "GET", path: `/submolts/${encodeURIComponent(name)}` });
  }

  subscribeToSubmolt(name: string): Promise<ApiSuccess> {
    return this.request({
      method: "POST",
      path: `/submolts/${encodeURIComponent(name)}/subscribe`,
    });
  }

  unsubscribeFromSubmolt(name: string): Promise<ApiSuccess> {
    return this.request({
      method: "DELETE",
      path: `/submolts/${encodeURIComponent(name)}/subscribe`,
    });
  }

  // Personalized feed
  getFeed(params?: GetFeedParams): Promise<Post[]> {
    return this.request({
      method: "GET",
      path: "/feed",
      query: params ? { sort: params.sort, limit: params.limit } : undefined,
    });
  }

  // Semantic search
  search(params: SearchParams): Promise<SearchResponse> {
    return this.request({
      method: "GET",
      path: "/search",
      query: { q: params.q, type: params.type, limit: params.limit },
    });
  }
}
